// Randomly pick variety directives so consecutive posts never share the same shape.
// Duplicated entries act as weights.
const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

// Content-aware hook eligibility. Some hook archetypes presuppose material that
// isn't in every source: NEWS REACTION needs an actual announcement, HARD NUMBER
// needs a concrete figure. classify_content inspects the source and flags both,
// so a hook the content cannot support is never assigned (which would otherwise
// force the writer off-source and get the post rejected by the reviewer).
const classification = $('classify_content').item.json.text || '';
const flag = (name) => new RegExp('"' + name + '"\\s*:\\s*true').test(classification);
const isNews = flag('is_news');
const hasHardNumber = flag('has_hard_number');

// These four archetypes work on any content.
const hooks = [
  'CONTRARIAN CLAIM: open with a blunt statement that challenges accepted practice',
  'WAR STORY: open with a concrete incident or observation from production work',
  'MISCONCEPTION: open by naming a common misconception and correcting it',
  'TRADE-OFF: open by framing the underlying trade-off most people ignore',
];
// These two are only eligible when the source actually supports them.
if (isNews) hooks.push('NEWS REACTION: open with your immediate, opinionated take on the announcement or release');
if (hasHardNumber) hooks.push('HARD NUMBER: open with a specific figure, cost, or metric and why it matters');

const hook = pick(hooks);

const format = pick([
  'PURE PROSE: no bullet points at all, 3-5 flowing paragraphs',
  'PURE PROSE: no bullet points at all, 3-5 flowing paragraphs',
  'PUNCHY: several very short paragraphs, at least two of them a single sentence',
  'PUNCHY: several very short paragraphs, at least two of them a single sentence',
  'ONE BULLET BLOCK: exactly one bullet list of 3-4 short items, with prose before and after',
]);

const length = pick([
  'SHORT: aim for roughly 40% of the word limit',
  'MEDIUM: aim for roughly 70% of the word limit',
  'MEDIUM: aim for roughly 70% of the word limit',
  'FULL: use most of the word limit',
]);

const closing = pick([
  'DIRECT QUESTION: end the body with one specific question to technical peers',
  'DIRECT QUESTION: end the body with one specific question to technical peers',
  'SHARED EXPERIENCE: end by inviting others to share how they handle it, phrased as a statement, no question mark',
  'HOT TAKE: end the body on a blunt one-line statement, no question, no invitation',
  'HOT TAKE: end the body on a blunt one-line statement, no question, no invitation',
  'NONE: end when the argument is complete, with no closing question or invitation',
]);

const VARIETY_DIRECTIVES = [
  `- Hook — ${hook}.`,
  `- Format — ${format}.`,
  `- Length — ${length}.`,
  `- Closing — ${closing}. The "Source here" line and hashtags always follow the body regardless.`,
].join('\n');

return [{ json: { ...$input.first().json, VARIETY_DIRECTIVES } }];

for (const item of $input.all()) {
  const { text } = item.json;

  const output = text.includes('<output>') && text.includes('</output>')
    ? text.split('<output>')[1].split('</output>')[0]
    : 'false';

  item.json.output = output;
}

return $input.all();

